INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('NIT Hamirpur', 'ambassador_message', 'hostels', 'all are 3 seaters except neelkath boys it is 1 seater. kbh (first year)', 'All hostels at NIT Hamirpur have 3-sharing rooms except Neelkanth boys hostel which has single rooms. KBH hostel is for first year students.', 2, '31/03/26 5:51 pm', '31/03/26 5:56 pm', 'whatsapp');
