INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('NIT Hamirpur', 'ambassador_message', 'medical_fines', 'End sem fine and backlog. hospitial in hostel(free)', 'Fines at NIT Hamirpur: End semester fine and backlog fines. Hospital available in hostel area, free for students.', 2, '31/03/26 6:05 pm', '31/03/26 6:07 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('NIT Hamirpur', 'ambassador_message', 'transport_restaurants', 'Airport (30km) dharmshala, 30km(una) railway station. Electric vehicles (are free 3) in college. Restaurant: hotspot, dominos, lapinous, lucknow food court. Both Swiggy and zomato, blinkit are there', 'Transport: Dharamshala Airport 30 km, Una Railway Station 30 km from campus. 3 free electric vehicles for campus transport. Nearby restaurants: Hotspot, Dominos, Lapinous, Lucknow Food Court. Swiggy, Zomato, and Blinkit deliver to campus.', 4, '31/03/26 6:10 pm', '31/03/26 6:12 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('NIT Hamirpur', 'ambassador_message', 'tourist_malls', 'Shimila,dharmshala,manali,chandigarh. alikrita mall,north stone,hideing mall', 'Tourist places near NIT Hamirpur: Shimla, Dharamshala, Manali, Chandigarh. Shopping malls: Alikrita Mall, North Stone, Hideing Mall.', 2, '31/03/26 6:03 pm', '31/03/26 6:08 pm', 'whatsapp');
